noncompliant:
// Noncompliant: Identical expressions in logical operators
void foo(int a, int b) {
    if (a == a) {  // Always true - likely copy/paste error
        // do something
    }

    if (b != b) {  // Always false - suspicious
        // unreachable code
    }
}

// Noncompliant: Identical expressions in comparison
void bar(int x, int y) {
    if (x > x) {  // Always false
        return;
    }

    bool result = (y && y);  // Redundant - same as just 'y'
}

compliant:
// Compliant: Different variables in comparison
void foo(int a, int b) {
    if (a == b) {  // Comparing different variables
        // do something
    }

    if (a != 0) {  // Comparing with different value
        // do something
    }
}

// Compliant: Bitwise operations (exceptions to the rule)
void bar(int x) {
    int result = x | x;  // Allowed for bitwise operations
    int mask = x & x;    // Allowed for bitwise operations
    int shifted = x << x; // Allowed for shift operations
}
